code_examples.insecureCode:
// ❌ Insecure: Only checks if the user is authenticated
app.get('/api/projects/:projectId', isAuthenticated, (req, res) => {
  const project = DB.projects.find(req.params.projectId);
  // Bug: This returns the project regardless of who owns it!
  res.json(project);
});

code_examples.secureCode:
// ✓ Secure: Scopes the query to the user's own project list
app.get('/api/projects/:projectId', isAuthenticated, (req, res) => {
  const project = DB.projects.findOne({
    _id: req.params.projectId,
    ownerId: req.user.id // Critical constraint
  });

  if (!project) return res.status(404).json({ error: 'Project not found or unauthorized.' });
  res.json(project);
});
